CREATE OR REPLACE FUNCTION fpa_gos_bank_name (as_memno char) RETURNS varchar AS $body$
DECLARE

  ls_bank_name sc_acc_m_ucf_bank.bank_name%type;

BEGIN
    select sc_acc_m_ucf_bank.bank_name into STRICT ls_bank_name
    from sc_mem_m_member_bank_accno
        ,sc_acc_m_ucf_bank
    where (sc_mem_m_member_bank_accno.bank_id = sc_acc_m_ucf_bank.bank_id)
    and (sc_mem_m_member_bank_accno.share_withdraw = '1')
    and (sc_mem_m_member_bank_accno.membership_no =  as_memno);

  return trim(both ls_bank_name);
exception
when too_many_rows then return null;
when no_data_found then return null;
end;
$body$
